    if (text && pairs.length < 3) pairs.push({type:'message(assistant)', ts, text});
  }
  if (p.type === 'agent_message') {
    const text = (p.message||'').slice(0,60);
    if (text && pairs.length < 6) pairs.push({type:'agent_message', ts, text});
  }
}
pairs.slice(0,6).forEach(p=>console.log(p));

// Check: same timestamp for same content?
let msgMap = new Map(), agentMap = new Map();
for (const line of lines) {
  const obj = JSON.parse(line);
  if (obj.type !== 'response_item' && obj.type !== 'event_msg') continue;
  const p = obj.payload || {};
  const ts = obj.timestamp;
  if (p.type === 'message' && (p.role||'').toLowerCase() === 'assistant') {
    const content = Array.isArray(p.content) ? p.content : [];
    const text = content.filter(b=>b&&['input_text','output_text','text'].includes((b.type||'').toLowerCase())).map(b=>b.text||'').join('\n').trim().slice(0,40);
    if (text) msgMap.set(text, ts);
  }
  if (p.type === 'agent_message') {
    const text = (p.message||'').trim().slice(0,40);
    if (text) agentMap.set(text, ts);
  }
}
let sameTsCnt = 0, diffTsCnt = 0;
for (const [text, ts] of msgMap) {
  if (agentMap.has(text)) {
    if (agentMap.get(text) === ts) sameTsCnt++;
    else { diffTsCnt++; if(diffTsCnt<=2) console.log('DIFF TS:', {text, msgTs:ts, agentTs:agentMap.get(text)}); }
  }
}
console.log('same timestamp duplicates:', sameTsCnt, '/ diff timestamp:', diffTsCnt);
